/*
 * Do not use. This This module only exists to verify the tag formatting.
 */

variable "tags" {
  description = "tags, which could be used for additional tags"
  type        = map(string)
}

resource "aws_iam_policy" "policy" {
  description = "A temporary policy. Should be deleted by the test."
  name_prefix = "test_policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "ec2:Describe*",
        ]
        Effect   = "Deny"
        Resource = "*"
      },
    ]
  })

  tags = var.tags
}

data "aws_caller_identity" "current" {}

resource "random_string" "instance_alias" {
  length  = 32
  special = false
  numeric = false
  upper   = false
}

module "amazon_connect" {
  # source  = "aws-ia/amazonconnect/aws"
  # version = ">= 0.0.1"

  source = "../../"

  instance_identity_management_type = "CONNECT_MANAGED"
  instance_inbound_calls_enabled    = true
  instance_outbound_calls_enabled   = true
  instance_alias                    = random_string.instance_alias.result

  # Instance Storage Configuration
  instance_storage_configs = {
    MEDIA_STREAMS = {
      storage_type = "KINESIS_VIDEO_STREAM"

      kinesis_video_stream_config = {
        prefix                 = "encrypted-media"
        retention_period_hours = 24

        encryption_config = {
          encryption_type = "KMS"
          key_id          = aws_kms_key.example.arn
        }
      }
    }
  }
}

# KMS Key
resource "aws_kms_key" "example" {
  policy              = data.aws_iam_policy_document.example_key_policy.json
  enable_key_rotation = true
}

data "aws_iam_policy_document" "example_key_policy" {
  # Key Administrators
  statement {
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }

    actions   = ["kms:*"]
    resources = ["*"]
  }

  # Key Users
  statement {
    principals {
      type        = "AWS"
      identifiers = [module.amazon_connect.instance.service_role]
    }

    actions = [
      "kms:Decrypt",
      "kms:DescribeKey",
      "kms:Encrypt",
      "kms:GenerateDataKey*",
      "kms:ReEncrypt*"
    ]
    resources = ["*"]
  }
}

resource "random_string" "instance_alias" {
  length  = 32
  special = false
  numeric = false
  upper   = false
}

module "amazon_connect" {
  # source  = "aws-ia/amazonconnect/aws"
  # version = ">= 0.0.1"

  source = "../../"

  instance_identity_management_type = "CONNECT_MANAGED"
  instance_inbound_calls_enabled    = true
  instance_outbound_calls_enabled   = true
  instance_alias                    = random_string.instance_alias.result

  # Lex Bot Associations
  bot_associations = {
    example = {
      name = aws_lex_bot.example.name
    }
  }
}

# Lex Bot
resource "aws_lex_bot" "example" {
  name             = "example"
  child_directed   = false
  process_behavior = "BUILD"

  intent {
    intent_name    = aws_lex_intent.example.name
    intent_version = aws_lex_intent.example.version
  }

  abort_statement {
    message {
      content      = "Sorry, I am not able to assist at this time."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I didn't understand you, what would you like to do?"
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "example" {
  name = "example"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "example one",
    "example two"
  ]
}

resource "random_pet" "this" {
  length = 2
}

resource "aws_cloudwatch_log_group" "this" {
  name = "log-group-${random_pet.this.id}"
}

resource "aws_cloudwatch_metric_stream" "this" {
  count = var.create ? 1 : 0

  name        = var.name
  name_prefix = var.name_prefix

  firehose_arn  = var.firehose_arn
  role_arn      = var.role_arn
  output_format = var.output_format

  dynamic "exclude_filter" {
    for_each = var.exclude_filter

    content {
      namespace    = exclude_filter.value.namespace
      metric_names = try(exclude_filter.value.metric_names, [])
    }
  }

  dynamic "include_filter" {
    for_each = var.include_filter

    content {
      namespace    = include_filter.value.namespace
      metric_names = try(include_filter.value.metric_names, [])
    }
  }

  dynamic "statistics_configuration" {
    for_each = var.statistics_configuration

    content {
      additional_statistics = statistics_configuration.value.additional_statistics

      dynamic "include_metric" {
        for_each = statistics_configuration.value.include_metric

        content {
          metric_name = include_metric.value.metric_name
          namespace   = include_metric.value.namespace
        }
      }
    }
  }

  tags = var.tags
}

# --- examples/service_network/main.tf ---

# Example 1: VPC Lattice service network created without auth policy
module "vpclattice_service_network_without_policy" {
  source = "../.."

  service_network = {
    name                  = "service-network-without-policy"
    auth_type             = "NONE"
    access_log_cloudwatch = aws_cloudwatch_log_group.service_network_loggroup.arn
    access_log_s3         = aws_s3_bucket.service_network_logbucket.arn
    access_log_firehose   = aws_kinesis_firehose_delivery_stream.service_network_deliverystream.arn
  }
}

# Example 2: VPC Lattice service network created with auth policy
module "vpclattice_service_network_with_policy" {
  source = "../.."

  service_network = {
    name      = "service-network-with-policy"
    auth_type = "AWS_IAM"
    auth_policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Action    = "*"
          Effect    = "Allow"
          Principal = "*"
          Resource  = "*"
          Condition = {
            StringNotEqualsIgnoreCase = {
              "aws:PrincipalType" = "anonymous"
            }
          }
        }
      ]
    })
  }
}

# Example 3: VPC Lattice service network reference (created outside the module)
resource "aws_vpclattice_service_network" "external_service_network" {
  name      = "external-service-network"
  auth_type = "NONE"
}

module "vpclattice_service_network_referenced" {
  source = "../.."

  service_network = {
    identifier = aws_vpclattice_service_network.external_service_network.id
  }
}

# Example 4: VPC Lattice service network VPC association
module "vpclattice_vpc_associations" {
  source = "../.."

  service_network = {
    identifier = aws_vpclattice_service_network.external_service_network.id
  }

  vpc_associations = { for k, v in module.vpcs : k => {
    vpc_id = v.vpc_attributes.id
  } }
}

# ---------- SUPPORT RESOURCES ----------
# Generate random string (for resources' names)
resource "random_string" "random" {
  length  = 8
  special = false
  upper   = false
}

# S3 Bucket
resource "aws_s3_bucket" "service_network_logbucket" {
  bucket        = "sn-logbucket-${random_string.random.result}"
  force_destroy = true
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "service_network_loggroup" {
  name              = "sn_loggroup-${random_string.random.result}"
  retention_in_days = 0
}

# Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "service_network_deliverystream" {
  name        = "sn-loggroup-firehose-${random_string.random.result}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.service_network_logbucket.arn
  }
}

# IAM Role (for Firehose Delivery Stream)
data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name               = "firehose_test_role"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

# VPCs
module "vpcs" {
  for_each = var.vpcs
  source   = "aws-ia/vpc/aws"
  version  = "4.4.4"

  name       = each.key
  cidr_block = each.value.cidr_block
  az_count   = each.value.number_azs

  subnets = {
    workload = { netmask = 28 }
  }
}

# --- modules/listener_rules/main.tf ---

# VPC Lattice Listener Rules
resource "aws_vpclattice_listener_rule" "lattice_listener_rule" {
  for_each = var.listener_rules

  name                = try(each.value.name, each.key)
  listener_identifier = var.listener_identifier
  service_identifier  = var.service_identifier
  priority            = each.value.priority

  match {
    http_match {
      method = try(each.value.http_match_method, null)

      # Dynamic block - header_matches
      dynamic "header_matches" {
        for_each = try(each.value.header_matches[*], [])
        content {
          case_sensitive = try(header_matches.value.case_sensitive, false)
          name           = header_matches.value.name

          match {
            contains = try(header_matches.value.contains, null)
            exact    = try(header_matches.value.exact, null)
            prefix   = try(header_matches.value.prefix, null)
          }
        }
      }

      # Dynamic block - path_match
      dynamic "path_match" {
        for_each = try(each.value.path_match[*], [])
        content {
          case_sensitive = try(path_match.value.case_sensitive, false)

          match {
            exact  = try(path_match.value.exact, null)
            prefix = try(path_match.value.prefix, null)
          }
        }
      }
    }
  }

  # Dynamic block - action = fixed_response
  dynamic "action" {
    for_each = try(each.value.action_fixedresponse[*], [])
    content {
      fixed_response {
        status_code = action.value.status_code
      }
    }
  }

  # Dynamic block - action = forward
  dynamic "action" {
    for_each = try(each.value.action_forward[*], [])
    content {
      forward {
        dynamic "target_groups" {
          for_each = try(action.value.target_groups, [])
          content {
            target_group_identifier = var.target_groups[target_groups.key]
            weight                  = target_groups.value.weight
          }
        }
      }
    }
  }

  tags = var.tags
}

# Create new ALB
resource "aws_lb" "polygon_nodes" {
  name_prefix = var.nodes_alb_name_prefix
  #tfsec:ignore:aws-elb-alb-not-public
  internal                   = false
  load_balancer_type         = "application"
  subnets                    = var.public_subnets
  security_groups            = [var.alb_sec_group]
  drop_invalid_header_fields = true


  tags = {
    Name = var.nodes_alb_name_tag
  }
}
# Create new ALB Target Group
resource "aws_lb_target_group" "polygon_nodes" {
  name_prefix = var.nodes_alb_targetgroup_name_prefix
  port        = 8545
  protocol    = "HTTP"
  vpc_id      = var.vpc_id
}

# Set http listener on ALB
resource "aws_lb_listener" "polygon_nodes_http" {
  load_balancer_arn = aws_lb.polygon_nodes.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type = "redirect"

    redirect {
      status_code = "HTTP_301"
      port        = 443
      protocol    = "HTTPS"
    }
  }
}

# Set https listener on ALB
resource "aws_lb_listener" "polygon_nodes_https" {
  load_balancer_arn = aws_lb.polygon_nodes.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-TLS-1-2-2017-01"
  certificate_arn   = var.alb_ssl_certificate

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.polygon_nodes.arn
  }
}

# Attach instances to ALB
resource "aws_lb_target_group_attachment" "polygon_nodes" {
  count = length(var.node_ids)

  target_group_arn = aws_lb_target_group.polygon_nodes.arn
  target_id        = var.node_ids[count.index]
  port             = 8545
}

# create the instance
resource "aws_instance" "polygon_edge_instance" {
  ami                  = data.aws_ami.ubuntu_20_04.id
  instance_type        = var.instance_type
  user_data_base64     = var.user_data_base64
  availability_zone    = var.az
  iam_instance_profile = var.instance_iam_role

  metadata_options {
    http_tokens   = "required"
    http_endpoint = "enabled"
  }

  root_block_device {
    encrypted = true
    tags = {
      Name = var.ebs_root_name_tag
    }
  }

  lifecycle {
    ignore_changes = [ami]
  }

  tags = {
    Name = var.instance_name
  }

  # attach the network interface
  network_interface {
    network_interface_id = aws_network_interface.instance_interface.id
    device_index         = 0
  }
}

# create the instance network interface
resource "aws_network_interface" "instance_interface" {
  subnet_id       = var.internal_subnet
  security_groups = var.internal_sec_groups

  tags = {
    Name = var.instance_interface_name_tag
  }
}

# create the EBS volume to hold the chain data
#tfsec:ignore:aws-ebs-encryption-customer-key
resource "aws_ebs_volume" "chain_data" {

  availability_zone = var.az
  size              = var.chain_data_ebs_volume_size
  encrypted         = true

  tags = {
    Name = var.chain_data_ebs_name_tag
  }
}

resource "aws_volume_attachment" "attach_chain_data" {

  device_name  = "/dev/sdf"
  volume_id    = aws_ebs_volume.chain_data.id
  instance_id  = aws_instance.polygon_edge_instance.id
  force_detach = true
}

provider "aws" {
  region = var.region
}

resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "custom-oac"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "custom-oai"
}

# Public S3 endpoint without any OAI/OAC
module "s3_plain" {
  source = "../../"

  origin_domain_name = var.origin_domain_name
  origin_type        = "custom"

  logging_enabled = var.logging_enabled
  context         = module.this.context
